/**
 * Integration tests for the full notification pipeline.
 *
 * Tests the end-to-end flow:
 *   EventBus → NotificationService → Adapters (email, SMS, webhook)
 *                                  → PreferencesService (gating)
 *                                  → NotificationHistoryService (logging)
 */

import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import { NotificationService, resetNotificationIdCounter } from '../../src/services/notification.service.js';
import { PreferencesService, resetPreferencesIdCounter } from '../../src/services/preferences.service.js';
import { NotificationHistoryService, resetNotificationLogIdCounter } from '../../src/services/notification-history.service.js';
import { EmailNotificationAdapter } from '../../src/adapters/email.adapter.js';
import { SmsNotificationAdapter } from '../../src/adapters/sms.adapter.js';
import { WebhookNotificationAdapter } from '../../src/adapters/webhook.adapter.js';
import { UserPreferencesRepository } from '../../src/repositories/user-preferences.repository.js';
import { NotificationLogRepository } from '../../src/repositories/notification-log.repository.js';
import { Database } from '../../src/utils/database.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';
import type { Order } from '../../src/models/order.js';
import type { User } from '../../src/models/user.js';

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function makeUser(overrides?: Partial<User>): User {
  return {
    id: 'user-1',
    name: 'Alice',
    email: 'alice@example.com',
    role: 'member',
    createdAt: new Date(),
    updatedAt: new Date(),
    ...overrides,
  };
}

function makeOrder(overrides?: Partial<Order>): Order {
  return {
    id: 'order-100',
    userId: 'user-1',
    items: [
      { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 9.99 },
      { productId: 'p2', name: 'Gadget', quantity: 1, unitPrice: 24.99 },
    ],
    total: 44.97,
    status: 'pending',
    createdAt: new Date(),
    updatedAt: new Date(),
    ...overrides,
  };
}

function orderCreatedEvent(user: User, order: Order): OrderCreatedEvent {
  return { type: 'order:created', order, user, timestamp: new Date() };
}

function orderStatusChangedEvent(
  order: Order,
  previousStatus: string,
  newStatus: string,
): OrderStatusChangedEvent {
  return { type: 'order:status-changed', order, previousStatus, newStatus, timestamp: new Date() };
}

// ---------------------------------------------------------------------------
// Test suite
// ---------------------------------------------------------------------------

describe('Notification Pipeline Integration', () => {
  let db: Database;
  let eventBus: EventBus;
  let emailAdapter: EmailNotificationAdapter;
  let smsAdapter: SmsNotificationAdapter;
  let webhookAdapter: WebhookNotificationAdapter;
  let preferencesService: PreferencesService;
  let historyService: NotificationHistoryService;
  let notificationService: NotificationService;

  beforeEach(() => {
    // Reset counters
    resetNotificationIdCounter();
    resetPreferencesIdCounter();
    resetNotificationLogIdCounter();

    // Fresh database and event bus
    db = new Database();
    eventBus = new EventBus();

    // Adapters
    emailAdapter = new EmailNotificationAdapter();
    smsAdapter = new SmsNotificationAdapter({ fromNumber: '+15559876543' });
    webhookAdapter = new WebhookNotificationAdapter({ url: 'https://hooks.example.com/notify' });

    // Repositories & services
    const prefsRepo = new UserPreferencesRepository(db);
    const logRepo = new NotificationLogRepository(db);
    preferencesService = new PreferencesService(prefsRepo);
    historyService = new NotificationHistoryService(logRepo);

    // Wire the full pipeline
    notificationService = new NotificationService(eventBus, preferencesService, historyService);
    notificationService.registerAdapter(emailAdapter);
    notificationService.registerAdapter(smsAdapter);
    notificationService.registerAdapter(webhookAdapter);
  });

  // -------------------------------------------------------------------------
  // Email channel — full pipeline via EventBus
  // -------------------------------------------------------------------------

  describe('Email notification delivery', () => {
    it('should send email notification when order is created', async () => {
      const user = makeUser();
      const order = makeOrder();

      await eventBus.emit(orderCreatedEvent(user, order));

      // Email adapter received the email
      const sentEmails = emailAdapter.getSentEmails();
      expect(sentEmails).toHaveLength(1);
      expect(sentEmails[0].to).toBe('alice@example.com');
      expect(sentEmails[0].subject).toContain('Order Confirmation');
      expect(sentEmails[0].subject).toContain('order-100');

      // Notification recorded in service
      const notifications = notificationService.getNotifications();
      expect(notifications).toHaveLength(1);
      expect(notifications[0].channel).toBe('email');
      expect(notifications[0].notificationType).toBe('order_confirmation');
      expect(notifications[0].status).toBe('sent');
    });

    it('should send email notification on order status change', async () => {
      const order = makeOrder({ status: 'confirmed' });

      await eventBus.emit(orderStatusChangedEvent(order, 'pending', 'confirmed'));

      const sentEmails = emailAdapter.getSentEmails();
      expect(sentEmails).toHaveLength(1);
      expect(sentEmails[0].subject).toContain('Order Update');
      expect(sentEmails[0].textBody).toContain('pending');
      expect(sentEmails[0].textBody).toContain('confirmed');
    });

    it('should send email with correct template rendering (HTML + text)', async () => {
      const user = makeUser();
      const order = makeOrder();

      await eventBus.emit(orderCreatedEvent(user, order));

      const email = emailAdapter.getSentEmails()[0];
      // HTML body should contain order confirmation heading
      expect(email.htmlBody).toContain('<h1>Order Confirmation</h1>');
      // Text body should contain item details
      expect(email.textBody).toContain('Widget x2');
      expect(email.textBody).toContain('Gadget x1');
      // Both should contain the total
      expect(email.textBody).toContain('$44.97');
    });

    it('should send email when user has email preferences enabled', async () => {
      const user = makeUser();
      const order = makeOrder();

      // Explicitly create preferences with email enabled
      preferencesService.createPreferences({
        userId: 'user-1',
        emailEnabled: true,
      });

      await eventBus.emit(orderCreatedEvent(user, order));

      expect(emailAdapter.getSentEmails()).toHaveLength(1);
      expect(notificationService.getNotifications()).toHaveLength(1);
    });
  });

  // -------------------------------------------------------------------------
  // SMS channel
  // -------------------------------------------------------------------------

  describe('SMS notification delivery', () => {
    it('should send SMS notification when triggered on SMS channel', async () => {
      const payload = {
        recipient: '+15551234567',
        subject: 'Order Confirmation: order-100',
        body: 'Your order has been placed.',
        channel: 'sms' as const,
        notificationType: 'order_confirmation' as const,
        metadata: { orderId: 'order-100', userId: 'user-1' },
      };

      // Trigger via the private sendNotification (integration test for SMS channel dispatch)
      await (notificationService as any).sendNotification(payload);

      const sentMessages = smsAdapter.getSentMessages();
      expect(sentMessages).toHaveLength(1);
      expect(sentMessages[0].message.to).toBe('+15551234567');
      expect(sentMessages[0].message.from).toBe('+15559876543');
      expect(sentMessages[0].message.body).toContain('Order Confirmation');

      const notifications = notificationService.getNotifications();
      expect(notifications).toHaveLength(1);
      expect(notifications[0].channel).toBe('sms');
      expect(notifications[0].status).toBe('sent');
    });

    it('should send SMS when user has SMS preferences enabled', async () => {
      preferencesService.createPreferences({
        userId: 'user-1',
        smsEnabled: true,
      });

      await (notificationService as any).sendNotification({
        recipient: '+15551234567',
        subject: 'Order Update',
        body: 'Your order has shipped.',
        channel: 'sms' as const,
        notificationType: 'order_status_update' as const,
        metadata: { userId: 'user-1' },
      });

      expect(smsAdapter.getSentMessages()).toHaveLength(1);
    });
  });

  // -------------------------------------------------------------------------
  // Webhook channel
  // -------------------------------------------------------------------------

  describe('Webhook notification delivery', () => {
    it('should send webhook notification when triggered on webhook channel', async () => {
      const payload = {
        recipient: 'system-hook',
        subject: 'Order Confirmation: order-100',
        body: 'Order placed by user-1',
        channel: 'webhook' as const,
        notificationType: 'order_confirmation' as const,
        metadata: { orderId: 'order-100', userId: 'user-1' },
      };

      await (notificationService as any).sendNotification(payload);

      const sentWebhooks = webhookAdapter.getSentWebhooks();
      expect(sentWebhooks).toHaveLength(1);
      expect(sentWebhooks[0].url).toBe('https://hooks.example.com/notify');
      expect(sentWebhooks[0].payload.event).toBe('order_confirmation');
      expect(sentWebhooks[0].payload.recipient).toBe('system-hook');
      expect(sentWebhooks[0].payload.metadata?.orderId).toBe('order-100');

      const notifications = notificationService.getNotifications();
      expect(notifications).toHaveLength(1);
      expect(notifications[0].channel).toBe('webhook');
      expect(notifications[0].status).toBe('sent');
    });

    it('should send webhook when user has webhook preferences enabled', async () => {
      preferencesService.createPreferences({
        userId: 'user-1',
        webhookEnabled: true,
      });

      await (notificationService as any).sendNotification({
        recipient: 'hook-endpoint',
        subject: 'User Welcome',
        body: 'Welcome!',
        channel: 'webhook' as const,
        notificationType: 'user_welcome' as const,
        metadata: { userId: 'user-1' },
      });

      expect(webhookAdapter.getSentWebhooks()).toHaveLength(1);
    });
  });

  // -------------------------------------------------------------------------
  // Notification history logging
  // -------------------------------------------------------------------------

  describe('Notification history', () => {
    it('should log email notification to history after EventBus event', async () => {
      const user = makeUser();
      const order = makeOrder();

      await eventBus.emit(orderCreatedEvent(user, order));

      const history = historyService.getAll();
      expect(history).toHaveLength(1);
      expect(history[0].channel).toBe('email');
      expect(history[0].notificationType).toBe('order_confirmation');
      expect(history[0].recipient).toBe('alice@example.com');
      expect(history[0].status).toBe('sent');
      expect(history[0].subject).toContain('Order Confirmation');
    });

    it('should log SMS notification to history', async () => {
      await (notificationService as any).sendNotification({
        recipient: '+15551234567',
        subject: 'Order Update',
        body: 'Shipped!',
        channel: 'sms' as const,
        notificationType: 'order_status_update' as const,
        metadata: { userId: 'user-1' },
      });

      const history = historyService.getAll();
      expect(history).toHaveLength(1);
      expect(history[0].channel).toBe('sms');
      expect(history[0].status).toBe('sent');
    });

    it('should log webhook notification to history', async () => {
      await (notificationService as any).sendNotification({
        recipient: 'hook',
        subject: 'Test',
        body: 'Body',
        channel: 'webhook' as const,
        notificationType: 'user_updated' as const,
        metadata: { userId: 'user-1' },
      });

      const history = historyService.getAll();
      expect(history).toHaveLength(1);
      expect(history[0].channel).toBe('webhook');
    });

    it('should log multiple notifications and support querying by user', async () => {
      const user = makeUser();
      const order = makeOrder();

      // Emit two events
      await eventBus.emit(orderCreatedEvent(user, order));
      await eventBus.emit(orderStatusChangedEvent(order, 'pending', 'confirmed'));

      const allHistory = historyService.getAll();
      expect(allHistory).toHaveLength(2);

      const userHistory = historyService.getByUser('user-1');
      expect(userHistory).toHaveLength(2);
    });

    it('should update history status to failed when adapter fails', async () => {
      // Create a webhook adapter with an unconfigured URL (will fail)
      const failingAdapter = new WebhookNotificationAdapter({ url: '' });
      notificationService.registerAdapter(failingAdapter);

      await (notificationService as any).sendNotification({
        recipient: 'hook',
        subject: 'Test',
        body: 'Body',
        channel: 'webhook' as const,
        notificationType: 'order_confirmation' as const,
        metadata: { userId: 'user-1' },
      });

      const history = historyService.getAll();
      expect(history).toHaveLength(1);
      expect(history[0].status).toBe('failed');
    });
  });

  // -------------------------------------------------------------------------
  // User preferences — channel gating
  // -------------------------------------------------------------------------

  describe('User preferences gating', () => {
    it('should NOT send email when email is disabled in preferences', async () => {
      const user = makeUser();
      const order = makeOrder();

      preferencesService.createPreferences({
        userId: 'user-1',
        emailEnabled: false,
      });

      await eventBus.emit(orderCreatedEvent(user, order));

      expect(emailAdapter.getSentEmails()).toHaveLength(0);
      expect(notificationService.getNotifications()).toHaveLength(0);
    });

    it('should NOT send SMS when SMS is disabled in preferences', async () => {
      preferencesService.createPreferences({
        userId: 'user-1',
        smsEnabled: false,
      });

      await (notificationService as any).sendNotification({
        recipient: '+15551234567',
        subject: 'Test',
        body: 'Body',
        channel: 'sms' as const,
        notificationType: 'order_confirmation' as const,
        metadata: { userId: 'user-1' },
      });

      expect(smsAdapter.getSentMessages()).toHaveLength(0);
      expect(notificationService.getNotifications()).toHaveLength(0);
    });

    it('should NOT send webhook when webhook is disabled in preferences', async () => {
      preferencesService.createPreferences({
        userId: 'user-1',
        webhookEnabled: false,
      });

      await (notificationService as any).sendNotification({
        recipient: 'hook',
        subject: 'Test',
        body: 'Body',
        channel: 'webhook' as const,
        notificationType: 'order_confirmation' as const,
        metadata: { userId: 'user-1' },
      });

      expect(webhookAdapter.getSentWebhooks()).toHaveLength(0);
      expect(notificationService.getNotifications()).toHaveLength(0);
    });

    it('should NOT send when notification category is unsubscribed', async () => {
      const user = makeUser();
      const order = makeOrder();

      preferencesService.createPreferences({
        userId: 'user-1',
        emailEnabled: true,
        subscribedCategories: ['order_status_update', 'user_welcome', 'user_updated'],
        // Note: order_confirmation is NOT in subscribedCategories
      });

      await eventBus.emit(orderCreatedEvent(user, order));

      expect(emailAdapter.getSentEmails()).toHaveLength(0);
      expect(notificationService.getNotifications()).toHaveLength(0);
    });

    it('should send notification when user has no preferences (opt-out model)', async () => {
      const user = makeUser();
      const order = makeOrder();

      // No preferences created — opt-out model means allow by default
      await eventBus.emit(orderCreatedEvent(user, order));

      expect(emailAdapter.getSentEmails()).toHaveLength(1);
      expect(notificationService.getNotifications()).toHaveLength(1);
    });

    it('should block one channel but allow another independently', async () => {
      preferencesService.createPreferences({
        userId: 'user-1',
        emailEnabled: false,
        smsEnabled: true,
      });

      const user = makeUser();
      const order = makeOrder();

      // Email (via EventBus) should be blocked
      await eventBus.emit(orderCreatedEvent(user, order));
      expect(emailAdapter.getSentEmails()).toHaveLength(0);

      // SMS should still work
      await (notificationService as any).sendNotification({
        recipient: '+15551234567',
        subject: 'Test',
        body: 'Body',
        channel: 'sms' as const,
        notificationType: 'order_confirmation' as const,
        metadata: { userId: 'user-1' },
      });
      expect(smsAdapter.getSentMessages()).toHaveLength(1);
    });

    it('should not log to history when notification is blocked by preferences', async () => {
      const user = makeUser();
      const order = makeOrder();

      preferencesService.createPreferences({
        userId: 'user-1',
        emailEnabled: false,
      });

      await eventBus.emit(orderCreatedEvent(user, order));

      expect(historyService.getAll()).toHaveLength(0);
    });
  });

  // -------------------------------------------------------------------------
  // Notification ordering
  // -------------------------------------------------------------------------

  describe('Notification ordering', () => {
    it('should deliver notifications in the order they were emitted', async () => {
      const user = makeUser();
      const order = makeOrder();

      // Emit two events in quick succession
      await eventBus.emit(orderCreatedEvent(user, order));
      await eventBus.emit(
        orderStatusChangedEvent(order, 'pending', 'confirmed'),
      );

      const notifications = notificationService.getNotifications();
      expect(notifications).toHaveLength(2);
      expect(notifications[0].notificationType).toBe('order_confirmation');
      expect(notifications[1].notificationType).toBe('order_status_update');

      // Email adapter should have received them in order too
      const emails = emailAdapter.getSentEmails();
      expect(emails).toHaveLength(2);
      expect(emails[0].subject).toContain('Order Confirmation');
      expect(emails[1].subject).toContain('Order Update');
    });

    it('should preserve order across multiple events for the same user', async () => {
      const user = makeUser();
      const order1 = makeOrder({ id: 'order-1' });
      const order2 = makeOrder({ id: 'order-2' });

      await eventBus.emit(orderCreatedEvent(user, order1));
      await eventBus.emit(orderCreatedEvent(user, order2));
      await eventBus.emit(
        orderStatusChangedEvent(order1, 'pending', 'confirmed'),
      );

      const notifications = notificationService.getNotifications();
      expect(notifications).toHaveLength(3);
      expect(notifications[0].subject).toContain('order-1');
      expect(notifications[1].subject).toContain('order-2');
      expect(notifications[2].subject).toContain('order-1');

      // History should match the same order
      const history = historyService.getAll();
      expect(history).toHaveLength(3);
      expect(history[0].metadata?.orderId).toBe('order-1');
      expect(history[1].metadata?.orderId).toBe('order-2');
      expect(history[2].metadata?.orderId).toBe('order-1');
    });
  });

  // -------------------------------------------------------------------------
  // Multi-channel dispatch
  // -------------------------------------------------------------------------

  describe('Multi-channel dispatch', () => {
    it('should dispatch to the correct adapter based on channel', async () => {
      // Send one on each channel
      await (notificationService as any).sendNotification({
        recipient: 'alice@example.com',
        subject: 'Email Test',
        body: 'Email body',
        channel: 'email' as const,
        notificationType: 'user_welcome' as const,
        metadata: { userId: 'user-1' },
      });

      await (notificationService as any).sendNotification({
        recipient: '+15551234567',
        subject: 'SMS Test',
        body: 'SMS body',
        channel: 'sms' as const,
        notificationType: 'user_welcome' as const,
        metadata: { userId: 'user-1' },
      });

      await (notificationService as any).sendNotification({
        recipient: 'webhook-endpoint',
        subject: 'Webhook Test',
        body: 'Webhook body',
        channel: 'webhook' as const,
        notificationType: 'user_welcome' as const,
        metadata: { userId: 'user-1' },
      });

      expect(emailAdapter.getSentEmails()).toHaveLength(1);
      expect(smsAdapter.getSentMessages()).toHaveLength(1);
      expect(webhookAdapter.getSentWebhooks()).toHaveLength(1);

      // All three should be logged to history
      expect(historyService.getAll()).toHaveLength(3);
      expect(notificationService.getNotifications()).toHaveLength(3);
    });

    it('should record notification even when no adapter is registered for the channel', async () => {
      // Create a service without the SMS adapter registered
      const minimalService = new NotificationService(eventBus, preferencesService, historyService);
      minimalService.registerAdapter(emailAdapter);
      // Deliberately NOT registering SMS adapter

      await (minimalService as any).sendNotification({
        recipient: '+15551234567',
        subject: 'SMS Test',
        body: 'No adapter',
        channel: 'sms' as const,
        notificationType: 'order_confirmation' as const,
      });

      // Notification should still be recorded
      const notifications = minimalService.getNotifications();
      expect(notifications).toHaveLength(1);
      expect(notifications[0].channel).toBe('sms');
      expect(notifications[0].status).toBe('sent');

      // But no SMS sent
      expect(smsAdapter.getSentMessages()).toHaveLength(0);
    });
  });
});

