+/**
+ * Integration tests for the full notification pipeline.
+ *
+ * Tests the end-to-end flow:
+ *   EventBus → NotificationService → Adapters (email, SMS, webhook)
+ *                                  → PreferencesService (gating)
+ *                                  → NotificationHistoryService (logging)
+ */
+
+import { describe, it, expect, beforeEach } from 'vitest';
+import { EventBus } from '../../src/events/event-bus.js';
+import { NotificationService, resetNotificationIdCounter } from '../../src/services/notification.service.js';
+import { PreferencesService, resetPreferencesIdCounter } from '../../src/services/preferences.service.js';
+import { NotificationHistoryService, resetNotificationLogIdCounter } from '../../src/services/notification-history.service.js';
+import { EmailNotificationAdapter } from '../../src/adapters/email.adapter.js';
+import { SmsNotificationAdapter } from '../../src/adapters/sms.adapter.js';
+import { WebhookNotificationAdapter } from '../../src/adapters/webhook.adapter.js';
+import { UserPreferencesRepository } from '../../src/repositories/user-preferences.repository.js';
+import { NotificationLogRepository } from '../../src/repositories/notification-log.repository.js';
+import { Database } from '../../src/utils/database.js';
+import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';
+import type { Order } from '../../src/models/order.js';
+import type { User } from '../../src/models/user.js';
+
+// ---------------------------------------------------------------------------
+// Helpers
+// ---------------------------------------------------------------------------
+
+function makeUser(overrides?: Partial<User>): User {
+  return {
+    id: 'user-1',
+    name: 'Alice',
+    email: 'alice@example.com',
+    role: 'member',
+    createdAt: new Date(),
+    updatedAt: new Date(),
+    ...overrides,
+  };
+}
+
+function makeOrder(overrides?: Partial<Order>): Order {
+  return {
+    id: 'order-100',
+    userId: 'user-1',
+    items: [
+      { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 9.99 },
+      { productId: 'p2', name: 'Gadget', quantity: 1, unitPrice: 24.99 },
+    ],
+    total: 44.97,
+    status: 'pending',
+    createdAt: new Date(),
+    updatedAt: new Date(),
+    ...overrides,
+  };
+}
+
+function orderCreatedEvent(user: User, order: Order): OrderCreatedEvent {
+  return { type: 'order:created', order, user, timestamp: new Date() };
+}
+
+function orderStatusChangedEvent(
+  order: Order,
+  previousStatus: string,
+  newStatus: string,
+  user?: User,
+): OrderStatusChangedEvent {
+  return {
+    type: 'order:status-changed',
+    order,
+    user: user ?? makeUser({ id: order.userId }),
+    previousStatus,
+    newStatus,
+    timestamp: new Date(),
+  };
+}
+
+// ---------------------------------------------------------------------------
+// Test suite
+// ---------------------------------------------------------------------------
+
+describe('Notification Pipeline Integration', () => {
+  let db: Database;
+  let eventBus: EventBus;
+  let emailAdapter: EmailNotificationAdapter;
+  let smsAdapter: SmsNotificationAdapter;
+  let webhookAdapter: WebhookNotificationAdapter;
+  let preferencesService: PreferencesService;
+  let historyService: NotificationHistoryService;
+  let notificationService: NotificationService;
+
+  beforeEach(() => {
+    // Reset counters
+    resetNotificationIdCounter();
+    resetPreferencesIdCounter();
+    resetNotificationLogIdCounter();
+
+    // Fresh database and event bus
+    db = new Database();
+    eventBus = new EventBus();
+
+    // Adapters
+    emailAdapter = new EmailNotificationAdapter();
+    smsAdapter = new SmsNotificationAdapter({ fromNumber: '+15559876543' });
+    webhookAdapter = new WebhookNotificationAdapter({ url: 'https://hooks.example.com/notify' });
+
+    // Repositories & services
+    const prefsRepo = new UserPreferencesRepository(db);
+    const logRepo = new NotificationLogRepository(db);
+    preferencesService = new PreferencesService(prefsRepo);
+    historyService = new NotificationHistoryService(logRepo);
+
+    // Wire the full pipeline
+    notificationService = new NotificationService(eventBus, preferencesService, historyService);
+    notificationService.registerAdapter(emailAdapter);
+    notificationService.registerAdapter(smsAdapter);
+    notificationService.registerAdapter(webhookAdapter);
+  });
+
+  // -------------------------------------------------------------------------
+  // Email channel — full pipeline via EventBus
+  // -------------------------------------------------------------------------
+
+  describe('Email notification delivery', () => {
+    it('should send email notification when order is created', async () => {
+      const user = makeUser();
+      const order = makeOrder();
+
+      await eventBus.emit(orderCreatedEvent(user, order));
+
+      // Email adapter received the email
+      const sentEmails = emailAdapter.getSentEmails();
+      expect(sentEmails).toHaveLength(1);
+      expect(sentEmails[0].to).toBe('alice@example.com');
+      expect(sentEmails[0].subject).toContain('Order Confirmation');
+      expect(sentEmails[0].subject).toContain('order-100');
+
+      // Notification recorded in service
+      const notifications = notificationService.getNotifications();
+      expect(notifications).toHaveLength(1);
+      expect(notifications[0].channel).toBe('email');
+      expect(notifications[0].notificationType).toBe('order_confirmation');
+      expect(notifications[0].status).toBe('sent');
+    });
+
+    it('should send email notification on order status change', async () => {
+      const order = makeOrder({ status: 'confirmed' });
+
+      await eventBus.emit(orderStatusChangedEvent(order, 'pending', 'confirmed'));
+
+      const sentEmails = emailAdapter.getSentEmails();
+      expect(sentEmails).toHaveLength(1);
+      expect(sentEmails[0].subject).toContain('Order Update');
+      expect(sentEmails[0].textBody).toContain('pending');
+      expect(sentEmails[0].textBody).toContain('confirmed');
+    });
+
+    it('should send email with correct template rendering (HTML + text)', async () => {
+      const user = makeUser();
+      const order = makeOrder();
+
+      await eventBus.emit(orderCreatedEvent(user, order));
+
+      const email = emailAdapter.getSentEmails()[0];
+      // HTML body should contain order confirmation heading
+      expect(email.htmlBody).toContain('<h1>Order Confirmation</h1>');
+      // Text body should contain item details
+      expect(email.textBody).toContain('Widget x2');
+      expect(email.textBody).toContain('Gadget x1');
+      // Both should contain the total
+      expect(email.textBody).toContain('$44.97');
+    });
+
+    it('should send email when user has email preferences enabled', async () => {
+      const user = makeUser();
+      const order = makeOrder();
+
+      // Explicitly create preferences with email enabled
+      preferencesService.createPreferences({
+        userId: 'user-1',
+        emailEnabled: true,
+      });
+
+      await eventBus.emit(orderCreatedEvent(user, order));
+
+      expect(emailAdapter.getSentEmails()).toHaveLength(1);
+      expect(notificationService.getNotifications()).toHaveLength(1);
+    });
+  });
+
+  // -------------------------------------------------------------------------
+  // SMS channel
+  // -------------------------------------------------------------------------
+
+  describe('SMS notification delivery', () => {
+    it('should send SMS notification when triggered on SMS channel', async () => {
+      const payload = {
+        recipient: '+15551234567',
+        subject: 'Order Confirmation: order-100',
+        body: 'Your order has been placed.',
+        channel: 'sms' as const,
+        notificationType: 'order_confirmation' as const,
+        metadata: { orderId: 'order-100', userId: 'user-1' },
+      };
+
+      // Trigger via the private sendNotification (integration test for SMS channel dispatch)
+      await (notificationService as any).sendNotification(payload);
+
+      const sentMessages = smsAdapter.getSentMessages();
+      expect(sentMessages).toHaveLength(1);
+      expect(sentMessages[0].message.to).toBe('+15551234567');
+      expect(sentMessages[0].message.from).toBe('+15559876543');
+      expect(sentMessages[0].message.body).toContain('Order Confirmation');
+
+      const notifications = notificationService.getNotifications();
+      expect(notifications).toHaveLength(1);
+      expect(notifications[0].channel).toBe('sms');
+      expect(notifications[0].status).toBe('sent');
+    });
+
+    it('should send SMS when user has SMS preferences enabled', async () => {
+      preferencesService.createPreferences({
+        userId: 'user-1',
+        smsEnabled: true,
+      });
+
+      await (notificationService as any).sendNotification({
+        recipient: '+15551234567',
+        subject: 'Order Update',
+        body: 'Your order has shipped.',
+        channel: 'sms' as const,
+        notificationType: 'order_status_update' as const,
+        metadata: { userId: 'user-1' },
